// scripts/merge-manual-battles.js
// Merges Data/manual-battles.json into Data/battles.json.
//
// Data/battles.json is generated by build-player-profiles.js.
// This script adds manual-only history rows back in and preserves manual fields.
//
// IMPORTANT:
// Manual dates win when provided.
// This prevents imported historical tables, like PoisonTurtlec0ld, from being sorted
// by their import created_at date instead of the real battle date.
//
// Manual fields are source of truth:
//   placement
//   update_number
//   update_url
//   api_battle_key
//   c0ld_results_table
//   clan_results_table
//   first_snapshot, last_snapshot when manually supplied
//
// Generated fields fill blanks:
//   first_snapshot
//   last_snapshot
//   total_snapshots
//   total_rows
//   unique_players

const fs = require("fs/promises");
const path = require("path");

const DATA_DIR = path.join(process.cwd(), "Data");
const GENERATED_FILE = path.join(DATA_DIR, "battles.json");
const MANUAL_FILE = path.join(DATA_DIR, "manual-battles.json");

function normalizeKey(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]/g, "");
}

function numberOrStringOrNull(value) {
  if (value === null || value === undefined || value === "") return null;

  if (typeof value === "string" && value.trim().toUpperCase() === "TBD") {
    return "TBD";
  }

  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function stringOrNull(value) {
  if (value === null || value === undefined || value === "") return null;
  return String(value);
}

function dateOrNull(value) {
  if (!value) return null;

  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d.toISOString();
}

function cleanRecord(record) {
  return {
    battle: stringOrNull(record.battle || record.display_name),
    display_name: stringOrNull(record.display_name || record.battle),

    api_battle_key: stringOrNull(record.api_battle_key),
    c0ld_results_table: stringOrNull(record.c0ld_results_table || record.player_results_table),
    clan_results_table: stringOrNull(record.clan_results_table),

    first_snapshot: dateOrNull(record.first_snapshot),
    last_snapshot: dateOrNull(record.last_snapshot),

    total_snapshots: numberOrStringOrNull(record.total_snapshots),
    total_rows: numberOrStringOrNull(record.total_rows),
    unique_players: numberOrStringOrNull(record.unique_players),

    placement: numberOrStringOrNull(record.placement),
    update_number: numberOrStringOrNull(record.update_number),
    update_url: stringOrNull(record.update_url)
  };
}

function mergeRecord(manual, generated) {
  return {
    battle: manual?.battle || generated?.battle || null,
    display_name: manual?.display_name || generated?.display_name || null,

    // Manual dates win when provided.
    // This fixes imported historical tables whose created_at is the import date.
    first_snapshot: manual?.first_snapshot ?? generated?.first_snapshot ?? null,
    last_snapshot: manual?.last_snapshot ?? generated?.last_snapshot ?? null,

    // Generated counts win when available.
    total_snapshots: generated?.total_snapshots ?? manual?.total_snapshots ?? null,
    total_rows: generated?.total_rows ?? manual?.total_rows ?? null,
    unique_players: generated?.unique_players ?? manual?.unique_players ?? null,

    placement: manual?.placement ?? generated?.placement ?? null,
    update_number: manual?.update_number ?? generated?.update_number ?? null,
    update_url: manual?.update_url ?? generated?.update_url ?? null,

    api_battle_key: manual?.api_battle_key ?? generated?.api_battle_key ?? null,
    c0ld_results_table: manual?.c0ld_results_table ?? generated?.c0ld_results_table ?? null,
    clan_results_table: manual?.clan_results_table ?? generated?.clan_results_table ?? null
  };
}

function sortBattles(a, b) {
  const au = Number(a.update_number);
  const bu = Number(b.update_number);

  const aHasUpdate = Number.isFinite(au);
  const bHasUpdate = Number.isFinite(bu);

  // Future-ready: once update numbers are filled in, sort by Update # first.
  if (aHasUpdate && bHasUpdate && au !== bu) {
    return bu - au;
  }

  // If only one has update_number, keep it above unknown update rows.
  if (aHasUpdate && !bHasUpdate) return -1;
  if (!aHasUpdate && bHasUpdate) return 1;

  // Fallback: sort by battle date.
  const ad = a.last_snapshot ? new Date(a.last_snapshot).getTime() : 0;
  const bd = b.last_snapshot ? new Date(b.last_snapshot).getTime() : 0;

  if (ad !== bd) return bd - ad;

  return String(a.display_name || a.battle || "").localeCompare(
    String(b.display_name || b.battle || "")
  );
}

async function readJsonArray(filePath) {
  try {
    const raw = await fs.readFile(filePath, "utf8");
    const parsed = JSON.parse(raw);

    if (!Array.isArray(parsed)) {
      throw new Error(`${filePath} must contain a JSON array.`);
    }

    return parsed;
  } catch (err) {
    if (err.code === "ENOENT") return [];
    throw err;
  }
}

async function main() {
  const generatedRaw = await readJsonArray(GENERATED_FILE);
  const manualRaw = await readJsonArray(MANUAL_FILE);

  const generatedMap = new Map();
  const manualMap = new Map();

  for (const raw of generatedRaw) {
    const record = cleanRecord(raw);
    if (!record.battle || !record.display_name) continue;

    generatedMap.set(normalizeKey(record.battle), record);
  }

  for (const raw of manualRaw) {
    const record = cleanRecord(raw);
    if (!record.battle || !record.display_name) continue;

    manualMap.set(normalizeKey(record.battle), record);
  }

  const allKeys = new Set([
    ...manualMap.keys(),
    ...generatedMap.keys()
  ]);

  const finalRecords = [];

  for (const key of allKeys) {
    const manual = manualMap.get(key) || null;
    const generated = generatedMap.get(key) || null;
    const merged = mergeRecord(manual, generated);

    if (merged.battle && merged.display_name) {
      finalRecords.push(merged);
    }
  }

  finalRecords.sort(sortBattles);

  await fs.writeFile(
    GENERATED_FILE,
    JSON.stringify(finalRecords, null, 2) + "\n",
    "utf8"
  );

  console.log(`Generated raw battles read: ${generatedRaw.length}`);
  console.log(`Manual raw battles read: ${manualRaw.length}`);
  console.log(`Generated unique battles: ${generatedMap.size}`);
  console.log(`Manual unique battles: ${manualMap.size}`);
  console.log(`Final battles written: ${finalRecords.length}`);
  console.log(`Updated ${GENERATED_FILE}`);

  console.log("Sorted battle output:");
  for (const battle of finalRecords) {
    console.log(
      `  ${battle.update_number ? `Update #${battle.update_number}` : "No update #"} | ` +
      `${battle.display_name} | ` +
      `${battle.last_snapshot || "no date"}`
    );
  }
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});
